/**
 * LLMemory-Palace v25.0 - Behavior Graph
 * Represents logic flows and their relationships
 */

import { createHash } from 'crypto';

export class BehaviorGraph {
  constructor() {
    this.flows = new Map();
    this._loadBuiltInFlows();
  }

  /**
   * Load built-in flows for common patterns
   */
  _loadBuiltInFlows() {
    // Authentication Flow (v12)
    this.register('AUTH_LOGIN', {
      steps: ['validate_input', 'hash_password', 'db_lookup_user', 'compare_hash', 'generate_jwt'],
      returns: 'token'
    });

    // Registration Flow
    this.register('AUTH_REGISTER', {
      steps: ['validate_input', 'check_existing_user', 'hash_password', 'create_user', 'generate_jwt'],
      returns: 'user'
    });

    // CRUD Create Flow
    this.register('CRUD_CREATE', {
      steps: ['validate_input', 'check_permissions', 'transform_data', 'db_insert', 'emit_event'],
      returns: 'created_entity'
    });

    // CRUD Read Flow
    this.register('CRUD_READ', {
      steps: ['validate_input', 'check_permissions', 'db_query', 'transform_response'],
      returns: 'entity'
    });

    // CRUD Update Flow
    this.register('CRUD_UPDATE', {
      steps: ['validate_input', 'check_permissions', 'fetch_existing', 'merge_data', 'db_update', 'emit_event'],
      returns: 'updated_entity'
    });

    // CRUD Delete Flow
    this.register('CRUD_DELETE', {
      steps: ['validate_input', 'check_permissions', 'check_dependencies', 'db_delete', 'emit_event'],
      returns: 'success'
    });

    // Order Processing Flow (v19)
    this.register('ORDER_PROCESS', {
      steps: ['validate_order', 'check_inventory', 'reserve_items', 'charge_payment', 'confirm_order', 'notify_user'],
      returns: 'order'
    });

    // API Request Flow
    this.register('API_REQUEST', {
      steps: ['authenticate', 'authorize', 'validate', 'process', 'respond'],
      returns: 'response'
    });

    // Error Handling Flow
    this.register('ERROR_HANDLING', {
      steps: ['catch_error', 'log_error', 'classify_error', 'format_response', 'send_response'],
      returns: 'error_response'
    });
  }

  /**
   * Register a new flow
   */
  register(name, flow) {
    this.flows.set(name, {
      name,
      steps: flow.steps,
      returns: flow.returns,
      hash: this._hash(name)
    });
  }

  /**
   * Get a flow by name
   */
  get(name) {
    return this.flows.get(name);
  }

  /**
   * Get all flows
   */
  getAll() {
    return this.flows.entries();
  }

  /**
   * Trace a flow and return detailed information
   */
  trace(flowName) {
    const flow = this.flows.get(flowName);
    if (!flow) {
      return `Flow "${flowName}" not found. Available: ${[...this.flows.keys()].join(', ')}`;
    }

    let output = `\n⚡ Flow: ${flowName}\n`;
    output += `   Hash: ${flow.hash}\n`;
    output += `   Returns: ${flow.returns}\n`;
    output += `   Steps:\n`;

    flow.steps.forEach((step, i) => {
      output += `     ${i + 1}. ${step}\n`;
    });

    return output;
  }

  /**
   * Extract flows from code content
   */
  extractFlows(content, language) {
    const flows = [];

    // Look for async function patterns that represent flows
    const asyncFuncRegex = /async\s+function\s+(\w+)\s*\([^)]*\)\s*\{([^}]+(?:\{[^}]*\}[^}]*)*)\}/g;
    let match;

    while ((match = asyncFuncRegex.exec(content)) !== null) {
      const name = match[1];
      const body = match[2];

      // Extract step-like calls
      const steps = [];
      const stepRegex = /(?:await\s+)?(\w+)\s*\(/g;
      let stepMatch;

      while ((stepMatch = stepRegex.exec(body)) !== null) {
        const stepName = stepMatch[1];
        if (!['console', 'return', 'if', 'while', 'for'].includes(stepName)) {
          steps.push(stepName);
        }
      }

      if (steps.length >= 2) {
        flows.push({
          name,
          steps,
          returns: 'unknown'
        });
      }
    }

    return flows;
  }

  /**
   * Find flows relevant to a module
   */
  findForModule(moduleName) {
    const flows = [];
    const lowerName = moduleName.toLowerCase();

    for (const [name, flow] of this.flows) {
      // Check if flow is related to module
      if (name.toLowerCase().includes(lowerName) ||
          flow.steps.some(s => s.toLowerCase().includes(lowerName))) {
        flows.push({ name, ...flow });
      }
    }

    return flows;
  }

  /**
   * List all flows
   */
  list() {
    const list = [];
    for (const [name, flow] of this.flows) {
      list.push({
        name,
        steps: flow.steps.length,
        returns: flow.returns
      });
    }
    return list;
  }

  /**
   * Generate flow diagram (ASCII)
   */
  diagram(flowName) {
    const flow = this.flows.get(flowName);
    if (!flow) return null;

    let diagram = `\n${flowName}\n`;
    diagram += '↓\n';

    flow.steps.forEach((step, i) => {
      diagram += `┌─────────────────┐\n`;
      diagram += `│ ${step.padEnd(15)} │\n`;
      diagram += `└────────┬────────┘\n`;

      if (i < flow.steps.length - 1) {
        diagram += '         ↓\n';
      }
    });

    diagram += `→ ${flow.returns}\n`;

    return diagram;
  }

  /**
   * Generate hash for flow
   */
  _hash(name) {
    return createHash('sha256')
      .update(name + JSON.stringify(this.flows.get(name)?.steps || []))
      .digest('hex')
      .substring(0, 8)
      .toUpperCase();
  }
}

/**
 * LLMemory-Palace v25.0 - Genome Encoder
 * One-line ultra-compressed genome generation
 * Full reconstruction support
 */

import { createHash } from 'crypto';
import { PatternLibrary } from './patterns.js';
import { BehaviorGraph } from './flows.js';
import { SemanticHash } from './semantic-hash.js';

export class GenomeEncoder {
  constructor() {
    this.patternLibrary = new PatternLibrary();
    this.behaviorGraph = new BehaviorGraph();
    this.semanticHash = new SemanticHash();
  }

  /**
   * Encode all files into a one-line genome
   */
  encode(files, patterns, flows, config) {
    const sections = [];

    // Version
    sections.push(`VERSION:v25`);

    // Patterns section
    const patternsSection = this._encodePatterns(patterns);
    sections.push(patternsSection);

    // Flows section
    const flowsSection = this._encodeFlows(flows);
    sections.push(flowsSection);

    // Entities section
    const entitiesSection = this._encodeEntities(files);
    sections.push(entitiesSection);

    // Config section
    const configSection = this._encodeConfig(config);
    sections.push(configSection);

    // Library section (compressed file references)
    const librarySection = this._encodeLibrary(files);
    sections.push(librarySection);

    return `GENOME|${sections.join('|')}`;
  }

  /**
   * Encode patterns to genome format
   */
  _encodePatterns(patterns) {
    const encoded = [];

    for (const [name, pattern] of patterns) {
      const template = pattern.template
        .replace(/"/g, '\\"')
        .replace(/\n/g, '\\n');

      const instances = pattern.instances
        .map(i => JSON.stringify(i))
        .join(',');

      encoded.push(`PATTERN:${name}->{template:"${template}",instances:[${instances}]}`);
    }

    return encoded.join('|');
  }

  /**
   * Encode flows to genome format
   */
  _encodeFlows(flows) {
    const encoded = [];

    for (const [name, flow] of flows) {
      const steps = flow.steps.map(s => `"${s}"`).join(',');
      encoded.push(`FLOW:${name}->{steps:[${steps}]}`);
    }

    return encoded.join('|');
  }

  /**
   * Encode entities from files
   */
  _encodeEntities(files) {
    const entities = new Set();

    for (const [filePath, file] of files) {
      // Extract class/function names as entities
      const classRegex = /class\s+(\w+)/g;
      const funcRegex = /(?:function|const|def)\s+(\w+)/g;

      let match;
      const content = file.content || '';

      while ((match = classRegex.exec(content)) !== null) {
        entities.add(match[1]);
      }
      while ((match = funcRegex.exec(content)) !== null) {
        entities.add(match[1]);
      }
    }

    return `ENTITIES:[${[...entities].map(e => `"${e}"`).join(',')}]`;
  }

  /**
   * Encode config
   */
  _encodeConfig(config) {
    return `CONFIG:${JSON.stringify({
      framework: config.framework || 'unknown',
      db: config.db || 'unknown',
      auth: config.auth || 'unknown',
      compressionLevel: config.compressionLevel || 3
    })}`;
  }

  /**
   * Encode library (file references with hashes)
   */
  _encodeLibrary(files) {
    const entries = [];

    for (const [filePath, file] of files) {
      const hash = createHash('sha256').update(file.content).digest('hex').substring(0, 8);
      entries.push(`FILE:${file.path}:${hash}:${file.lines}`);
    }

    return `LIBRARY:[${entries.join(',')}]`;
  }

  /**
   * Decode genome string back to files
   */
  decode(genomeString) {
    const sections = genomeString.split('|');
    const result = {
      version: null,
      patterns: [],
      flows: [],
      entities: [],
      config: {},
      library: []
    };

    for (const section of sections) {
      if (section.startsWith('VERSION:')) {
        result.version = section.substring(8);
      } else if (section.startsWith('PATTERN:')) {
        const pattern = this._parsePattern(section.substring(8));
        if (pattern) result.patterns.push(pattern);
      } else if (section.startsWith('FLOW:')) {
        const flow = this._parseFlow(section.substring(5));
        if (flow) result.flows.push(flow);
      } else if (section.startsWith('ENTITIES:')) {
        try {
          result.entities = JSON.parse(section.substring(9));
        } catch { result.entities = []; }
      } else if (section.startsWith('CONFIG:')) {
        try {
          result.config = JSON.parse(section.substring(7));
        } catch { result.config = {}; }
      } else if (section.startsWith('LIBRARY:')) {
        result.library = this._parseLibrary(section.substring(8));
      }
    }

    return result;
  }

  /**
   * Parse pattern from genome section
   */
  _parsePattern(str) {
    const match = str.match(/(\w+)->\{template:"(.+)",instances:\[(.+)\]\}/);
    if (!match) return null;

    return {
      name: match[1],
      template: match[2],
      instances: JSON.parse(`[${match[3]}]`)
    };
  }

  /**
   * Parse flow from genome section
   */
  _parseFlow(str) {
    const match = str.match(/(\w+)->\{steps:\[(.+)\]\}/);
    if (!match) return null;

    try {
      return {
        name: match[1],
        steps: JSON.parse(`[${match[2]}]`)
      };
    } catch {
      return { name: match[1], steps: [] };
    }
  }

  /**
   * Parse library section (non-standard format)
   */
  _parseLibrary(str) {
    // Format: [FILE:path:hash:lines,FILE:path:hash:lines,...]
    const files = [];
    const fileRegex = /FILE:([^:]+):([^:]+):(\d+)/g;
    let match;

    while ((match = fileRegex.exec(str)) !== null) {
      files.push({
        path: match[1],
        hash: match[2],
        lines: parseInt(match[3])
      });
    }

    return files;
  }

  /**
   * Reconstruct source files from genome
   */
  reconstruct(genomeString, outputDir) {
    const genome = this.decode(genomeString);
    const patternMap = new Map();

    // Build pattern lookup
    for (const pattern of genome.patterns) {
      patternMap.set(pattern.name, pattern);
    }

    // Reconstruct each file
    const files = [];
    const libraryFiles = genome.library || [];

    for (const fileRef of libraryFiles) {
      // Handle both string format and object format
      let filePath, fileHash, fileLines;

      if (typeof fileRef === 'object' && fileRef.path) {
        filePath = fileRef.path;
        fileHash = fileRef.hash;
        fileLines = fileRef.lines;
      } else if (typeof fileRef === 'string') {
        [filePath, fileHash, fileLines] = fileRef.split(':');
      } else {
        continue;
      }

      // Find matching patterns for this file
      const matchingPatterns = genome.patterns.filter(p => 
        p.instances.some(i => filePath.includes(i.entity || ''))
      );

      // Generate content from patterns
      let content = '';
      for (const pattern of matchingPatterns) {
        const instance = pattern.instances.find(i => filePath.includes(i.entity || ''));
        if (instance) {
          let expanded = pattern.template;
          for (const [key, value] of Object.entries(instance)) {
            expanded = expanded.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
          }
          content += expanded + '\n\n';
        }
      }

      files.push({
        path: filePath,
        hash: fileHash,
        lines: parseInt(fileLines) || 0,
        content
      });
    }

    return files;
  }

  /**
   * Get compression statistics
   */
  getStats(genomeString) {
    return {
      length: genomeString.length,
      tokenEstimate: Math.ceil(genomeString.length / 4),
      patternCount: (genomeString.match(/PATTERN:/g) || []).length,
      flowCount: (genomeString.match(/FLOW:/g) || []).length,
      entityCount: (genomeString.match(/ENTITIES:/g) || []).length
    };
  }
}

/**
 * LLMemory-Palace v25.0
 * Main package exports
 * 
 * Ultra-compressed code genome system for LLM context transfer.
 * 500-2000x compression with full reconstruction.
 */

// Core classes
export { Palace } from './palace.js';
export { PatternLibrary } from './patterns.js';
export { BehaviorGraph } from './flows.js';
export { SemanticHash } from './semantic-hash.js';
export { GenomeEncoder } from './genome.js';
export { Reconstructor } from './reconstructor.js';

// Version info
export const VERSION = '25.0.0';
export const NAME = 'llmemory-palace';

// Default export
export default Palace;

/**
 * LLMemory-Palace v25.0 - Main Palace Class
 * Ultra-compressed code genome system for LLM context transfer
 * 
 * Features:
 * - Pattern library with template expansion
 * - Behavior graphs for flow detection
 * - Semantic hashing for deduplication
 * - One-line genome generation
 * - Full reconstruction support
 */

import fs from 'fs';
import path from 'path';
import { createHash } from 'crypto';
import { PatternLibrary } from './patterns.js';
import { BehaviorGraph } from './flows.js';
import { SemanticHash } from './semantic-hash.js';
import { GenomeEncoder } from './genome.js';

export class Palace {
  constructor(projectPath) {
    this.projectPath = projectPath;
    this.patternLibrary = new PatternLibrary();
    this.behaviorGraph = new BehaviorGraph();
    this.semanticHash = new SemanticHash();
    this.genomeEncoder = new GenomeEncoder();
    this.files = new Map();
    this.patterns = new Map();
    this.flows = new Map();
    this.entities = new Map();
    this.config = {
      compressionLevel: 3,
      languages: [],
      framework: null,
      db: null,
      auth: null
    };
  }

  /**
   * Initialize palace for a project
   */
  async init() {
    const palaceDir = path.join(this.projectPath, '.palace');
    const stateDir = path.join(palaceDir, 'state');
    const outputDir = path.join(palaceDir, 'output');

    // Create directories
    [palaceDir, stateDir, outputDir].forEach(dir => {
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }
    });

    // Create initial state
    const state = {
      version: '25.0.0',
      created: new Date().toISOString(),
      projectPath: this.projectPath,
      files: [],
      patterns: [],
      flows: [],
      entities: [],
      config: this.config
    };

    fs.writeFileSync(
      path.join(stateDir, 'history.json'),
      JSON.stringify(state, null, 2)
    );

    return state;
  }

  /**
   * Scan project directory
   */
  async scan() {
    const excludePatterns = this._getExcludePatterns();
    const files = [];

    const scanDir = (dir) => {
      const entries = fs.readdirSync(dir, { withFileTypes: true });

      for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);

        if (entry.isDirectory()) {
          // Skip excluded directories
          if (excludePatterns.some(p => entry.name.match(p))) {
            continue;
          }
          scanDir(fullPath);
        } else if (entry.isFile()) {
          // Skip excluded files
          if (excludePatterns.some(p => fullPath.match(p))) {
            continue;
          }

          const content = fs.readFileSync(fullPath, 'utf-8');
          const language = this._detectLanguage(fullPath);
          const hash = this._hashContent(content);

          const fileEntry = {
            path: path.relative(this.projectPath, fullPath),
            fullPath,
            language,
            hash,
            size: content.length,
            lines: content.split('\n').length,
            content
          };

          // Extract patterns from file
          const patterns = this.patternLibrary.extractPatterns(content, language);
          fileEntry.patterns = patterns;

          // Extract flows from file
          const flows = this.behaviorGraph.extractFlows(content, language);
          fileEntry.flows = flows;

          files.push(fileEntry);
          this.files.set(fullPath, fileEntry);
        }
      }
    };

    scanDir(this.projectPath);

    // Detect project config
    this._detectConfig(files);

    return {
      files: files.length,
      lines: files.reduce((sum, f) => sum + f.lines, 0),
      size: files.reduce((sum, f) => sum + f.size, 0),
      languages: [...new Set(files.map(f => f.language))],
      patterns: files.reduce((sum, f) => sum + f.patterns.length, 0),
      flows: files.reduce((sum, f) => sum + f.flows.length, 0)
    };
  }

  /**
   * Export to CXML format
   */
  async export(options = {}) {
    const { format = 'cxml', level = 3, compress = false } = options;

    await this.scan();

    const timestamp = new Date().toISOString();
    const stats = this._getStats();

    let output = '';

    // Header
    output += `<?xml version="1.0" encoding="UTF-8"?>\n`;
    output += `<!--\n${this._generateBanner(timestamp, stats)}\n-->\n`;
    output += `<PALACE version="25.0" project="${this._getProjectName()}" generated="${timestamp}">\n\n`;

    // Vestibulum (metadata)
    output += this._generateVestibulum();

    // Pattern Library (v25 feature)
    output += this._generatePatternLibrary();

    // Behavior Graph (v25 feature)
    output += this._generateBehaviorGraph();

    // Genome section (v25 feature)
    output += this._generateGenomeSection();

    // Library (file contents)
    output += this._generateLibrary(level, compress);

    output += '\n</PALACE>\n';

    return output;
  }

  /**
   * Generate one-line genome (v25 feature)
   */
  async generateGenome() {
    await this.scan();
    return this.genomeEncoder.encode(this.files, this.patterns, this.flows, this.config);
  }

  /**
   * Compress with pattern library
   */
  async compress() {
    const scanResult = await this.scan();

    const originalSize = scanResult.size;
    let compressedContent = '';

    for (const [filePath, file] of this.files) {
      // Apply pattern compression
      const compressed = this.patternLibrary.compress(file.content, file.language);

      // Apply semantic hashing
      const hashed = this.semanticHash.compress(compressed);

      compressedContent += hashed;
    }

    const compressedSize = Buffer.byteLength(compressedContent, 'utf8');
    const ratio = (originalSize / compressedSize).toFixed(1);

    return {
      originalSize,
      compressedSize,
      ratio,
      content: compressedContent
    };
  }

  /**
   * Interactive LLM query (v25 feature)
   */
  async query(queryStr) {
    const q = queryStr.toUpperCase();

    if (q.includes('TRACE FLOW')) {
      const flowName = queryStr.match(/TRACE FLOW\s+(\w+)/i)?.[1];
      return this.behaviorGraph.trace(flowName);
    }

    if (q.includes('SHOW PATTERN')) {
      const patternName = queryStr.match(/SHOW PATTERN\s+(\w+)/i)?.[1];
      return this.patternLibrary.get(patternName);
    }

    if (q.includes('GENERATE MODULE')) {
      const moduleName = queryStr.match(/GENERATE MODULE\s+(\w+)/i)?.[1];
      return this._generateModule(moduleName);
    }

    if (q.includes('LIST PATTERNS')) {
      return this.patternLibrary.list();
    }

    if (q.includes('LIST FLOWS')) {
      return this.behaviorGraph.list();
    }

    return `Unknown query. Try: TRACE FLOW <name>, SHOW PATTERN <name>, GENERATE MODULE <name>`;
  }

  /**
   * Get compression ratio
   */
  getCompressionRatio() {
    const stats = this._getStats();
    const genome = this.genomeEncoder.encode(this.files, this.patterns, this.flows, this.config);
    return Math.round(stats.size / genome.length);
  }

  /**
   * Get current status
   */
  async getStatus() {
    await this.scan();
    const stats = this._getStats();
    return {
      name: this._getProjectName(),
      files: stats.files,
      lines: stats.lines,
      size: stats.size,
      patterns: this.patterns.size,
      flows: this.flows.size,
      issues: this._detectIssues().length
    };
  }

  /**
   * Analyze complexity
   */
  async analyzeComplexity() {
    await this.scan();

    let totalComplexity = 0;
    let maxComplexity = 0;
    const highComplexityFiles = [];

    for (const [filePath, file] of this.files) {
      const complexity = this._calculateComplexity(file);
      file.complexity = complexity;
      totalComplexity += complexity;
      maxComplexity = Math.max(maxComplexity, complexity);

      if (complexity > 15) {
        highComplexityFiles.push({ path: file.path, complexity });
      }
    }

    return {
      average: (totalComplexity / this.files.size).toFixed(1),
      max: maxComplexity,
      highCount: highComplexityFiles.length,
      highFiles: highComplexityFiles
    };
  }

  // ==================== Private Methods ====================

  _getExcludePatterns() {
    return [
      /^node_modules$/,
      /^\.git$/,
      /^\.palace$/,
      /^dist$/,
      /^__pycache__$/,
      /\.pyc$/,
      /\.md$/,
      /\.txt$/,
      /\.rst$/,
      /package-lock\.json$/,
      /yarn\.lock$/
    ];
  }

  _detectLanguage(filePath) {
    const ext = path.extname(filePath).toLowerCase();
    const langMap = {
      '.js': 'JavaScript',
      '.jsx': 'JavaScript',
      '.ts': 'TypeScript',
      '.tsx': 'TypeScript',
      '.py': 'Python',
      '.go': 'Go',
      '.rs': 'Rust',
      '.java': 'Java',
      '.kt': 'Kotlin',
      '.rb': 'Ruby',
      '.php': 'PHP',
      '.c': 'C',
      '.cpp': 'C++',
      '.h': 'C',
      '.hpp': 'C++',
      '.cs': 'C#',
      '.swift': 'Swift',
      '.json': 'JSON',
      '.yaml': 'YAML',
      '.yml': 'YAML',
      '.toml': 'TOML',
      '.sql': 'SQL',
      '.sh': 'Shell',
      '.bash': 'Shell'
    };
    return langMap[ext] || 'Unknown';
  }

  _hashContent(content) {
    return createHash('sha256').update(content).digest('hex').substring(0, 16);
  }

  _getProjectName() {
    return path.basename(this.projectPath);
  }

  _getStats() {
    let totalSize = 0;
    let totalLines = 0;

    for (const [_, file] of this.files) {
      totalSize += file.size;
      totalLines += file.lines;
    }

    return {
      files: this.files.size,
      lines: totalLines,
      size: totalSize
    };
  }

  _detectConfig(files) {
    // Detect framework
    const hasPackage = files.some(f => f.path === 'package.json');
    const hasRequirements = files.some(f => f.path === 'requirements.txt');
    const hasCargo = files.some(f => f.path === 'Cargo.toml');
    const hasGoMod = files.some(f => f.path === 'go.mod');

    if (hasPackage) {
      this.config.framework = 'Node.js';
      try {
        const pkg = JSON.parse(fs.readFileSync(path.join(this.projectPath, 'package.json'), 'utf-8'));
        if (pkg.dependencies?.express) this.config.framework = 'Express';
        if (pkg.dependencies?.next) this.config.framework = 'Next.js';
        if (pkg.dependencies?.fastify) this.config.framework = 'Fastify';
      } catch {}
    }

    if (hasRequirements) {
      this.config.framework = this.config.framework || 'Python';
    }

    if (hasCargo) {
      this.config.framework = 'Rust';
    }

    if (hasGoMod) {
      this.config.framework = 'Go';
    }
  }

  _detectIssues() {
    const issues = [];

    for (const [filePath, file] of this.files) {
      // Check for TODO/FIXME
      const todoMatches = file.content.match(/TODO|FIXME|HACK|XXX/gi);
      if (todoMatches) {
        issues.push({
          file: file.path,
          type: 'INFO',
          message: `Found ${todoMatches.length} TODO/FIXME comments`
        });
      }

      // Check for console.log
      const consoleMatches = file.content.match(/console\.log|print\(/g);
      if (consoleMatches && consoleMatches.length > 3) {
        issues.push({
          file: file.path,
          type: 'WARNING',
          message: `High number of debug statements: ${consoleMatches.length}`
        });
      }
    }

    return issues;
  }

  _calculateComplexity(file) {
    let complexity = 1;
    const content = file.content;

    // Count decision points
    const ifMatches = content.match(/\bif\s*\(/g) || [];
    const forMatches = content.match(/\bfor\s*\(/g) || [];
    const whileMatches = content.match(/\bwhile\s*\(/g) || [];
    const caseMatches = content.match(/\bcase\s+/g) || [];
    const catchMatches = content.match(/\bcatch\s*\(/g) || [];
    const andMatches = content.match(/&&|\|\|/g) || [];
    const ternaryMatches = content.match(/\?/g) || [];

    complexity += ifMatches.length;
    complexity += forMatches.length;
    complexity += whileMatches.length;
    complexity += caseMatches.length;
    complexity += catchMatches.length;
    complexity += Math.floor(andMatches.length / 2);
    complexity += ternaryMatches.length;

    return complexity;
  }

  _generateBanner(timestamp, stats) {
    return `
╔══════════════════════════════════════════════════════════════════╗
║  LLMemory-Palace v25.0 | ${timestamp}
║  COPY THIS ENTIRE DOCUMENT TO ANY LLM
║  
║  Project: ${this._getProjectName()}
║  Files: ${stats.files} | Lines: ${stats.lines.toLocaleString()} | Size: ${this._formatSize(stats.size)}
║  Patterns: ${this.patterns.size} | Flows: ${this.flows.size}
╚══════════════════════════════════════════════════════════════════╝
    `.trim();
  }

  _formatSize(bytes) {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  }

  _generateVestibulum() {
    const stats = this._getStats();
    return ` <VESTIBULUM>
  <FOCUS>export</FOCUS>
  <SESSION>${new Date().toISOString()}</SESSION>
  <FILES>${stats.files}</FILES>
  <LINES>${stats.lines}</LINES>
  <SIZE>${this._formatSize(stats.size)}</SIZE>
  <PATTERNS>${this.patterns.size}</PATTERNS>
  <FLOWS>${this.flows.size}</FLOWS>
  <CONFIG>${JSON.stringify(this.config)}</CONFIG>
 </VESTIBULUM>\n\n`;
  }

  _generatePatternLibrary() {
    let output = ' <GENOME>\n';
    output += '  <PATTERNS>\n';

    for (const [name, pattern] of this.patternLibrary.getAll()) {
      output += `   <PATTERN id="${name}" hash="${this.semanticHash.hash(name)}">\n`;
      output += `    <TEMPLATE><![CDATA[${pattern.template}]]></TEMPLATE>\n`;
      if (pattern.instances.length > 0) {
        output += `    <INSTANCES>${JSON.stringify(pattern.instances)}</INSTANCES>\n`;
      }
      output += '   </PATTERN>\n';
    }

    output += '  </PATTERNS>\n';
    return output;
  }

  _generateBehaviorGraph() {
    let output = '  <FLOWS>\n';

    for (const [name, flow] of this.behaviorGraph.getAll()) {
      output += `   <FLOW id="${name}" hash="${this.semanticHash.hash(name)}">\n`;
      output += `    <STEPS>${JSON.stringify(flow.steps)}</STEPS>\n`;
      output += '   </FLOW>\n';
    }

    output += '  </FLOWS>\n\n';
    return output;
  }

  _generateGenomeSection() {
    const stats = this._getStats();
    let output = '  <ENTITIES>\n';

    for (const [name, entity] of this.entities) {
      output += `   <ENTITY name="${name}" type="${entity.type}" hash="${this.semanticHash.hash(name)}"/>\n`;
    }

    output += '  </ENTITIES>\n';
    output += `  <CONFIG>${JSON.stringify(this.config)}</CONFIG>\n`;
    output += ' </GENOME>\n\n';
    return output;
  }

  _generateLibrary(level, compress) {
    const stats = this._getStats();
    let output = ` <LIBRARY files="${stats.files}" lines="${stats.lines}" size="${this._formatSize(stats.size)}">\n`;
    output += `  <LANGUAGES>${JSON.stringify([...new Set([...this.files.values()].map(f => f.language))])}</LANGUAGES>\n`;
    output += `  <DEPENDENCIES count="${this._countDependencies()}"/>\n`;

    for (const [filePath, file] of this.files) {
      output += this._generateFileEntry(file, level, compress);
    }

    output += ' </LIBRARY>\n';
    return output;
  }

  _generateFileEntry(file, level, compress) {
    let output = `  <Φ path="${file.path}" lang="${file.language}" lines="${file.lines}" complexity="${file.complexity || 1}" hash="${file.hash}">\n`;

    // Structure
    output += `   <S>${JSON.stringify({
      classes: file.patterns?.filter(p => p.type === 'class').map(p => p.name) || [],
      functions: file.patterns?.filter(p => p.type === 'function').map(p => p.name) || [],
      constants: [],
      variables: []
    })}</S>\n`;

    // Imports
    const imports = this._extractImports(file);
    output += `   <I>${JSON.stringify(imports)}</I>\n`;

    // Exports
    const exports = this._extractExports(file);
    output += `   <E>${JSON.stringify(exports)}</E>\n`;

    // Content (CDATA)
    if (level >= 3) {
      const content = compress ? this.patternLibrary.compress(file.content, file.language) : file.content;
      output += `   <C><![CDATA[${this._escapeCdata(content)}]]></C>\n`;
    }

    output += '  </Φ>\n';
    return output;
  }

  _escapeCdata(content) {
    return content.replace(/\]\]>/g, ']]]]><![CDATA[>');
  }

  _extractImports(file) {
    const imports = [];
    const importRegex = /(?:import\s+.*?from\s+['"](.*?)['"]|require\s*\(\s*['"](.*?)['"]\s*\)|from\s+['"](.*?)['"]\s+import)/g;
    let match;

    while ((match = importRegex.exec(file.content)) !== null) {
      imports.push(match[1] || match[2] || match[3]);
    }

    return imports;
  }

  _extractExports(file) {
    const exports = [];
    const exportRegex = /(?:export\s+(?:default\s+)?(?:function|class|const|let|var)\s+(\w+)|module\.exports\s*=\s*(\w+))/g;
    let match;

    while ((match = exportRegex.exec(file.content)) !== null) {
      exports.push(match[1] || match[2]);
    }

    return exports;
  }

  _countDependencies() {
    let count = 0;
    for (const [_, file] of this.files) {
      count += this._extractImports(file).length;
    }
    return count;
  }

  _generateModule(moduleName) {
    // Generate code for a module using patterns
    const patterns = this.patternLibrary.findForModule(moduleName);
    const flows = this.behaviorGraph.findForModule(moduleName);

    let code = `// Auto-generated module: ${moduleName}\n\n`;

    // Generate from patterns
    for (const pattern of patterns) {
      code += this.patternLibrary.expand(pattern, { module: moduleName }) + '\n\n';
    }

    // Generate from flows
    for (const flow of flows) {
      code += `// Flow: ${flow.name}\n`;
      for (const step of flow.steps) {
        code += `// - ${step}\n`;
      }
      code += '\n';
    }

    return code;
  }

  /**
   * Get all patterns from the pattern library
   */
  async getPatterns() {
    const patterns = {};
    for (const [name, pattern] of this.patternLibrary.patterns) {
      patterns[name] = pattern;
    }
    return patterns;
  }

  /**
   * Get all flows from the behavior graph
   */
  async getFlows() {
    const flows = {};
    for (const [name, flow] of this.behaviorGraph.flows) {
      flows[name] = flow;
    }
    return flows;
  }

  /**
   * Analyze dependencies in the codebase
   */
  async analyzeDependencies() {
    if (this.files.size === 0) {
      await this.scan();
    }

    const dependencies = new Set();
    const graph = new Map();

    for (const [filePath, file] of this.files) {
      const imports = this._extractImports(file);
      graph.set(filePath, imports);
      imports.forEach(imp => dependencies.add(imp));
    }

    // Detect circular dependencies
    const cycles = this._detectCycles(graph);

    return {
      total: dependencies.size,
      cycles: cycles.length,
      cyclePaths: cycles,
      graph: Object.fromEntries(graph)
    };
  }

  /**
   * Detect circular dependencies in the dependency graph
   */
  _detectCycles(graph) {
    const cycles = [];
    const visited = new Set();
    const recStack = new Set();

    const dfs = (node, path) => {
      visited.add(node);
      recStack.add(node);

      const neighbors = graph.get(node) || [];
      for (const neighbor of neighbors) {
        if (!visited.has(neighbor)) {
          const cycle = dfs(neighbor, [...path, neighbor]);
          if (cycle) cycles.push(cycle);
        } else if (recStack.has(neighbor)) {
          // Found cycle
          const cycleStart = path.indexOf(neighbor);
          if (cycleStart !== -1) {
            cycles.push(path.slice(cycleStart).concat(neighbor));
          }
        }
      }

      recStack.delete(node);
      return null;
    };

    for (const [node] of graph) {
      if (!visited.has(node)) {
        dfs(node, [node]);
      }
    }

    return cycles;
  }

  /**
   * Create a packable/mergeable package of the entire codebase
   */
  async createPack() {
    if (this.files.size === 0) {
      await this.scan();
    }

    const pack = {
      version: '25.0.0',
      name: this._getProjectName(),
      created: new Date().toISOString(),
      stats: {
        files: this.files.size,
        lines: [...this.files.values()].reduce((sum, f) => sum + f.lines, 0),
        size: [...this.files.values()].reduce((sum, f) => sum + f.size, 0)
      },
      config: this.config,
      files: [],
      patterns: [],
      flows: [],
      entities: []
    };

    // Add all files with full content
    for (const [filePath, file] of this.files) {
      pack.files.push({
        path: file.path,
        content: file.content,
        language: file.language,
        lines: file.lines,
        hash: file.hash
      });
    }

    // Add patterns from library
    for (const [name, pattern] of this.patternLibrary.patterns) {
      pack.patterns.push({
        name,
        template: pattern.template,
        instances: pattern.instances || []
      });
    }

    // Add flows from behavior graph
    for (const [name, flow] of this.behaviorGraph.flows) {
      pack.flows.push({
        name,
        steps: flow.steps,
        returns: flow.returns
      });
    }

    // Add entities
    for (const [name, entity] of this.entities) {
      pack.entities.push({
        name,
        type: entity.type,
        file: entity.file
      });
    }

    return pack;
  }

  /**
   * Merge a pack into this project
   */
  async mergePack(pack, outputDir = './merged') {
    const fullPath = path.resolve(outputDir);

    // Create output directory
    if (!fs.existsSync(fullPath)) {
      fs.mkdirSync(fullPath, { recursive: true });
    }

    let mergedFiles = 0;

    // Write all files
    for (const file of pack.files) {
      const filePath = path.join(fullPath, file.path);
      const dir = path.dirname(filePath);

      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }

      fs.writeFileSync(filePath, file.content, 'utf-8');
      mergedFiles++;
    }

    // Write palace metadata
    const palaceDir = path.join(fullPath, '.palace');
    if (!fs.existsSync(palaceDir)) {
      fs.mkdirSync(palaceDir, { recursive: true });
    }

    // Write patterns
    if (pack.patterns && pack.patterns.length > 0) {
      fs.writeFileSync(
        path.join(palaceDir, 'patterns.json'),
        JSON.stringify(pack.patterns, null, 2)
      );
    }

    // Write flows
    if (pack.flows && pack.flows.length > 0) {
      fs.writeFileSync(
        path.join(palaceDir, 'flows.json'),
        JSON.stringify(pack.flows, null, 2)
      );
    }

    // Write pack metadata
    fs.writeFileSync(
      path.join(palaceDir, 'pack.json'),
      JSON.stringify({
        name: pack.name,
        version: pack.version,
        created: pack.created,
        mergedAt: new Date().toISOString()
      }, null, 2)
    );

    return { files: mergedFiles, outputDir: fullPath };
  }
}

/**
 * LLMemory-Palace v25.0 - Pattern Library
 * Stores and expands code patterns for compression
 */

import { createHash } from 'crypto';

export class PatternLibrary {
  constructor() {
    this.patterns = new Map();
    this._loadBuiltInPatterns();
  }

  /**
   * Load built-in patterns for common code constructs
   */
  _loadBuiltInPatterns() {
    // CRUD Pattern (v11)
    this.register('CRUD_ENTITY', {
      template: `async function {action}{entity}(id) {
  return db.{entity}.{method}({id});
}`,
      instances: []
    });

    // Express Route Pattern (v12)
    this.register('EXPRESS_ROUTE', {
      template: `app.{method}("{path}", async (req, res) => {
  {logic}
});`,
      instances: []
    });

    // Repository Pattern
    this.register('REPOSITORY', {
      template: `class {name}Repository {
  async findById(id) { return this.db.{table}.findUnique({ where: { id } }); }
  async findAll() { return this.db.{table}.findMany(); }
  async create(data) { return this.db.{table}.create({ data }); }
  async update(id, data) { return this.db.{table}.update({ where: { id }, data }); }
  async delete(id) { return this.db.{table}.delete({ where: { id } }); }
}`,
      instances: []
    });

    // Service Pattern
    this.register('SERVICE', {
      template: `class {name}Service {
  constructor(repository) {
    this.repository = repository;
  }

  async {method}(...args) {
    // Business logic here
    return this.repository.{repoMethod}(...args);
  }
}`,
      instances: []
    });

    // Controller Pattern
    this.register('CONTROLLER', {
      template: `class {name}Controller {
  constructor(service) {
    this.service = service;
  }

  async {method}(req, res) {
    const result = await this.service.{serviceMethod}(req.body);
    res.json(result);
  }
}`,
      instances: []
    });

    // Middleware Pattern
    this.register('MIDDLEWARE', {
      template: `function {name}Middleware(req, res, next) {
  // {description}
  next();
}`,
      instances: []
    });

    // Test Pattern
    this.register('TEST', {
      template: `describe('{name}', () => {
  it('should {behavior}', async () => {
    // Arrange
    // Act
    // Assert
    expect(result).toBeDefined();
  });
});`,
      instances: []
    });

    // Type Definition Pattern
    this.register('TYPEDEF', {
      template: `interface {name} {
  {fields}
}`,
      instances: []
    });

    // Error Handler Pattern
    this.register('ERROR_HANDLER', {
      template: `class {name}Error extends Error {
  constructor(message, code = '{code}') {
    super(message);
    this.code = code;
    this.name = '{name}Error';
  }
}`,
      instances: []
    });

    // Validation Pattern
    this.register('VALIDATOR', {
      template: `function validate{name}(data) {
  const errors = [];
  {validations}
  return { valid: errors.length === 0, errors };
}`,
      instances: []
    });
  }

  /**
   * Register a new pattern
   */
  register(name, pattern) {
    this.patterns.set(name, {
      name,
      template: pattern.template,
      instances: pattern.instances || [],
      hash: this._hash(pattern.template)
    });
  }

  /**
   * Get a pattern by name
   */
  get(name) {
    return this.patterns.get(name);
  }

  /**
   * Get all patterns
   */
  getAll() {
    return this.patterns.entries();
  }

  /**
   * Add an instance to a pattern
   */
  addInstance(patternName, instance) {
    const pattern = this.patterns.get(patternName);
    if (pattern) {
      pattern.instances.push(instance);
    }
  }

  /**
   * Extract patterns from code content
   */
  extractPatterns(content, language) {
    const patterns = [];

    // Extract class definitions
    const classRegex = /class\s+(\w+)(?:\s+extends\s+(\w+))?\s*\{/g;
    let match;
    while ((match = classRegex.exec(content)) !== null) {
      patterns.push({
        type: 'class',
        name: match[1],
        extends: match[2] || null,
        pattern: 'CLASS'
      });
    }

    // Extract function definitions
    const funcRegex = /(?:async\s+)?function\s+(\w+)\s*\(|const\s+(\w+)\s*=\s*(?:async\s+)?\(?/g;
    while ((match = funcRegex.exec(content)) !== null) {
      const name = match[1] || match[2];
      if (name && !name.startsWith('_')) {
        patterns.push({
          type: 'function',
          name,
          pattern: 'FUNCTION'
        });
      }
    }

    // Extract arrow functions
    const arrowRegex = /(?:const|let|var)\s+(\w+)\s*=\s*(?:async\s+)?\([^)]*\)\s*=>/g;
    while ((match = arrowRegex.exec(content)) !== null) {
      patterns.push({
        type: 'function',
        name: match[1],
        pattern: 'ARROW_FUNCTION'
      });
    }

    // Extract Express routes
    const routeRegex = /app\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"]+)['"]/g;
    while ((match = routeRegex.exec(content)) !== null) {
      patterns.push({
        type: 'route',
        method: match[1].toUpperCase(),
        path: match[2],
        pattern: 'EXPRESS_ROUTE'
      });
    }

    // Extract imports
    const importRegex = /import\s+.*?from\s+['"]([^'"]+)['"]/g;
    while ((match = importRegex.exec(content)) !== null) {
      patterns.push({
        type: 'import',
        module: match[1],
        pattern: 'IMPORT'
      });
    }

    return patterns;
  }

  /**
   * Expand a pattern with given parameters
   */
  expand(patternName, params) {
    const pattern = this.patterns.get(patternName);
    if (!pattern) return null;

    let result = pattern.template;
    for (const [key, value] of Object.entries(params)) {
      result = result.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
    }

    return result;
  }

  /**
   * Compress content by replacing patterns
   */
  compress(content, language) {
    let compressed = content;

    // Try to match and replace known patterns
    for (const [name, pattern] of this.patterns) {
      const instances = this._findPatternInstances(content, pattern.template);

      for (const instance of instances) {
        // Replace with pattern reference
        const ref = `@PATTERN:${name}:${JSON.stringify(instance.params)}`;
        compressed = compressed.replace(instance.match, ref);
      }
    }

    return compressed;
  }

  /**
   * Find instances of a pattern in content
   */
  _findPatternInstances(content, template) {
    const instances = [];

    // Convert template to regex pattern
    const regexStr = template
      .replace(/\{(\w+)\}/g, '(.+?)')
      .replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

    try {
      const regex = new RegExp(regexStr, 'g');
      let match;

      while ((match = regex.exec(content)) !== null) {
        // Extract parameters from match groups
        const params = {};
        const paramNames = template.match(/\{(\w+)\}/g) || [];

        paramNames.forEach((name, i) => {
          params[name.slice(1, -1)] = match[i + 1];
        });

        instances.push({
          match: match[0],
          params
        });
      }
    } catch (e) {
      // Invalid regex, skip
    }

    return instances;
  }

  /**
   * Find patterns suitable for a module
   */
  findForModule(moduleName) {
    const patterns = [];

    for (const [name, pattern] of this.patterns) {
      // Check if pattern is relevant to module
      if (pattern.instances.some(i => 
        i.entity?.toLowerCase() === moduleName.toLowerCase() ||
        i.name?.toLowerCase() === moduleName.toLowerCase()
      )) {
        patterns.push({ name, ...pattern });
      }
    }

    return patterns;
  }

  /**
   * List all patterns
   */
  list() {
    const list = [];
    for (const [name, pattern] of this.patterns) {
      list.push({
        name,
        instances: pattern.instances.length,
        template: pattern.template.substring(0, 60) + '...'
      });
    }
    return list;
  }

  /**
   * Generate hash for a template
   */
  _hash(template) {
    return createHash('sha256')
      .update(template)
      .digest('hex')
      .substring(0, 8)
      .toUpperCase();
  }
}

/**
 * LLMemory-Palace v25.0 - Reconstructor
 * Reconstructs source files from CXML or genome
 */

import fs from 'fs';
import path from 'path';
import { GenomeEncoder } from './genome.js';
import { PatternLibrary } from './patterns.js';

export class Reconstructor {
  constructor() {
    this.genomeEncoder = new GenomeEncoder();
    this.patternLibrary = new PatternLibrary();
  }

  /**
   * Reconstruct source from CXML or genome file
   */
  async rebuild(inputFile, outputDir = './reconstructed') {
    const content = fs.readFileSync(inputFile, 'utf-8');

    // Detect format
    if (content.includes('<PALACE')) {
      await this._reconstructFromCxml(content, outputDir);
    } else if (content.startsWith('GENOME|')) {
      await this._reconstructFromGenome(content, outputDir);
    } else {
      throw new Error('Unknown format. Expected CXML or genome.');
    }

    return outputDir;
  }

  /**
   * Reconstruct from CXML format
   */
  async _reconstructFromCxml(cxmlContent, outputDir) {
    // Create output directory
    if (!fs.existsSync(outputDir)) {
      fs.mkdirSync(outputDir, { recursive: true });
    }

    // Extract files from CXML
    const fileRegex = /<Φ[^>]*path="([^"]+)"[^>]*>[\s\S]*?<C><!\[CDATA\[([\s\S]*?)\]\]><\/C>[\s\S]*?<\/Φ>/g;
    let match;

    while ((match = fileRegex.exec(cxmlContent)) !== null) {
      const filePath = match[1];
      let content = match[2];

      // Unescape CDATA
      content = content.replace(/\]\]\]\]><!\[CDATA\[>/g, ']]>');

      // Create full path
      const fullPath = path.join(outputDir, filePath);
      const dir = path.dirname(fullPath);

      // Ensure directory exists
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }

      // Write file
      fs.writeFileSync(fullPath, content, 'utf-8');
      console.log(`  Reconstructed: ${filePath}`);
    }
  }

  /**
   * Reconstruct from one-line genome format
   */
  async _reconstructFromGenome(genomeString, outputDir) {
    // Create output directory
    if (!fs.existsSync(outputDir)) {
      fs.mkdirSync(outputDir, { recursive: true });
    }

    const genome = this.genomeEncoder.decode(genomeString);
    const files = this.genomeEncoder.reconstruct(genomeString, outputDir);

    // Write each file
    for (const file of files) {
      const fullPath = path.join(outputDir, file.path);
      const dir = path.dirname(fullPath);

      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }

      fs.writeFileSync(fullPath, file.content, 'utf-8');
      console.log(`  Reconstructed: ${file.path}`);
    }

    // Also generate flows
    for (const flow of genome.flows) {
      const flowContent = this._generateFlowFile(flow);
      const flowPath = path.join(outputDir, 'flows', `${flow.name}_flow.js`);

      const flowDir = path.dirname(flowPath);
      if (!fs.existsSync(flowDir)) {
        fs.mkdirSync(flowDir, { recursive: true });
      }

      fs.writeFileSync(flowPath, flowContent, 'utf-8');
      console.log(`  Generated flow: ${flow.name}`);
    }

    // Generate config
    const configPath = path.join(outputDir, 'config.json');
    fs.writeFileSync(configPath, JSON.stringify(genome.config, null, 2), 'utf-8');
    console.log(`  Generated config: config.json`);
  }

  /**
   * Generate flow file from flow definition
   */
  _generateFlowFile(flow) {
    let content = `/**\n * Flow: ${flow.name}\n * Auto-generated by LLMemory-Palace\n */\n\n`;
    content += `async function ${flow.name}() {\n`;

    for (let i = 0; i < flow.steps.length; i++) {
      content += `  // Step ${i + 1}: ${flow.steps[i]}\n`;
      content += `  await ${flow.steps[i]}();\n\n`;
    }

    content += `  return result;\n`;
    content += `}\n`;
    content += `\nmodule.exports = { ${flow.name} };\n`;

    return content;
  }

  /**
   * Reconstruct a single pattern instance
   */
  reconstructPattern(patternName, params) {
    return this.patternLibrary.expand(patternName, params);
  }

  /**
   * Verify reconstruction matches original
   */
  verify(originalContent, reconstructedContent) {
    // Normalize whitespace
    const normalize = (str) => str.replace(/\s+/g, ' ').trim();

    return normalize(originalContent) === normalize(reconstructedContent);
  }
}

/**
 * LLMemory-Palace v25.0 - Semantic Hash
 * Provides semantic hashing for deduplication
 */

import { createHash } from 'crypto';

export class SemanticHash {
  constructor() {
    this.hashTable = new Map();
    this.reverseTable = new Map();
  }

  /**
   * Generate a semantic hash for a name/string
   */
  hash(name) {
    // Check cache first
    if (this.hashTable.has(name)) {
      return this.hashTable.get(name);
    }

    // Generate short hash
    const fullHash = createHash('sha256')
      .update(name)
      .digest('hex')
      .substring(0, 8)
      .toUpperCase();

    this.hashTable.set(name, fullHash);
    this.reverseTable.set(fullHash, name);

    return fullHash;
  }

  /**
   * Resolve a hash back to its original name
   */
  resolve(hashCode) {
    return this.reverseTable.get(hashCode) || null;
  }

  /**
   * Compress content by replacing names with hashes
   */
  compress(content) {
    let compressed = content;

    // Find all identifier-like strings
    const identifierRegex = /\b([A-Z][a-zA-Z0-9_]*)\b/g;
    let match;

    while ((match = identifierRegex.exec(content)) !== null) {
      const identifier = match[1];

      // Skip very short identifiers (not worth hashing)
      if (identifier.length <= 3) continue;

      const hashCode = this.hash(identifier);

      // Only replace if we save space
      if (identifier.length > hashCode.length) {
        compressed = compressed.replace(new RegExp(`\\b${identifier}\\b`, 'g'), `#${hashCode}`);
      }
    }

    return compressed;
  }

  /**
   * Decompress content by replacing hashes with names
   */
  decompress(content) {
    let decompressed = content;

    // Find all hash references
    const hashRegex = /#([A-F0-9]{8})/g;
    let match;

    while ((match = hashRegex.exec(content)) !== null) {
      const hashCode = match[1];
      const originalName = this.resolve(hashCode);

      if (originalName) {
        decompressed = decompressed.replace(`#${hashCode}`, originalName);
      }
    }

    return decompressed;
  }

  /**
   * Get the hash table for serialization
   */
  getHashTable() {
    return Object.fromEntries(this.hashTable);
  }

  /**
   * Load a hash table
   */
  loadHashTable(table) {
    for (const [name, hash] of Object.entries(table)) {
      this.hashTable.set(name, hash);
      this.reverseTable.set(hash, name);
    }
  }

  /**
   * Find similar strings using hash prefixes
   */
  findSimilar(name, threshold = 2) {
    const hash1 = this.hash(name);
    const similar = [];

    for (const [existingName, existingHash] of this.hashTable) {
      // Count matching characters
      let matches = 0;
      for (let i = 0; i < Math.min(hash1.length, existingHash.length); i++) {
        if (hash1[i] === existingHash[i]) matches++;
      }

      if (matches >= threshold && existingName !== name) {
        similar.push({ name: existingName, hash: existingHash, similarity: matches });
      }
    }

    return similar.sort((a, b) => b.similarity - a.similarity);
  }
}

