/**
 * LLMemory-Palace v25.0 Test Suite
 * Tests the actual implemented API
 */

import { Palace } from '../lib/palace.js';
import { PatternLibrary } from '../lib/patterns.js';
import { BehaviorGraph } from '../lib/flows.js';
import { SemanticHash } from '../lib/semantic-hash.js';
import { GenomeEncoder } from '../lib/genome.js';
import { Reconstructor } from '../lib/reconstructor.js';

const tests = [];
let passed = 0;
let failed = 0;

function test(name, fn) {
  tests.push({ name, fn });
}

function assertEqual(actual, expected, msg = '') {
  if (actual !== expected) {
    throw new Error(`${msg} Expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`);
  }
}

function assertContains(str, substr, msg = '') {
  if (typeof str !== 'string') {
    throw new Error(`${msg} Expected string, got ${typeof str}`);
  }
  if (!str.includes(substr)) {
    throw new Error(`${msg} Expected to contain "${substr}"`);
  }
}

function assertTrue(value, msg = '') {
  if (!value) {
    throw new Error(`${msg} Expected truthy value, got ${value}`);
  }
}

// ============================================
// PatternLibrary Tests
// ============================================

test('PatternLibrary initializes with built-in patterns', () => {
  const lib = new PatternLibrary();
  assertTrue(lib.patterns.size > 0, 'Should have patterns');
  const crudPattern = lib.get('CRUD_ENTITY');
  assertTrue(crudPattern !== undefined, 'Should have CRUD pattern');
});

test('PatternLibrary extracts patterns from code', () => {
  const lib = new PatternLibrary();
  const code = `
    async function getUser(id) {
      return db.users.findUnique({ where: { id } });
    }
  `;
  const matches = lib.extractPatterns(code, 'javascript');
  assertTrue(matches.length > 0, 'Should extract patterns');
});

test('PatternLibrary expands pattern with params', () => {
  const lib = new PatternLibrary();
  const expanded = lib.expand('CRUD_ENTITY', {
    action: 'get',
    entity: 'User',
    method: 'findUnique'
  });
  assertContains(expanded, 'getUser', 'Should include function name');
});

test('PatternLibrary registers new patterns', () => {
  const lib = new PatternLibrary();
  lib.register('MY_PATTERN', {
    template: 'function {name}() { return {value}; }',
    instances: []
  });
  const pattern = lib.get('MY_PATTERN');
  assertTrue(pattern !== undefined, 'Should register pattern');
});

// ============================================
// BehaviorGraph Tests
// ============================================

test('BehaviorGraph initializes with built-in flows', () => {
  const graph = new BehaviorGraph();
  assertTrue(graph.flows.size > 0, 'Should have flows');
});

test('BehaviorGraph returns flow by name', () => {
  const graph = new BehaviorGraph();
  const flow = graph.get('AUTH_LOGIN');
  assertTrue(flow !== undefined, 'Should find AUTH_LOGIN flow');
  assertTrue(flow.steps && flow.steps.length > 0, 'Should have steps');
});

test('BehaviorGraph traces flows', () => {
  const graph = new BehaviorGraph();
  const trace = graph.trace('AUTH_LOGIN');
  assertContains(trace, 'AUTH_LOGIN', 'Should include flow name');
  assertContains(trace, 'validate_input', 'Should include steps');
});

test('BehaviorGraph lists all flows', () => {
  const graph = new BehaviorGraph();
  const list = graph.list();
  assertTrue(Array.isArray(list), 'Should return array');
  assertTrue(list.length > 0, 'Should have flows');
});

// ============================================
// SemanticHash Tests
// ============================================

test('SemanticHash generates hash', () => {
  const hasher = new SemanticHash();
  const hash = hasher.hash('testName');
  assertTrue(typeof hash === 'string', 'Should return string hash');
  assertTrue(hash.length === 8, 'Hash should be 8 characters');
});

test('SemanticHash is deterministic', () => {
  const hasher = new SemanticHash();
  const hash1 = hasher.hash('testName');
  const hash2 = hasher.hash('testName');
  assertEqual(hash1, hash2, 'Same input should produce same hash');
});

test('SemanticHash resolves hashes back to names', () => {
  const hasher = new SemanticHash();
  const hash = hasher.hash('MyClassName');
  const resolved = hasher.resolve(hash);
  assertEqual(resolved, 'MyClassName', 'Should resolve to original name');
});

test('SemanticHash finds similar code', () => {
  const hasher = new SemanticHash();
  hasher.hash('getUserById');
  hasher.hash('getUserByName');
  const similar = hasher.findSimilar('getUserById');
  assertTrue(Array.isArray(similar), 'Should return array');
});

// ============================================
// GenomeEncoder Tests
// ============================================

test('GenomeEncoder encodes project', () => {
  const encoder = new GenomeEncoder();
  const files = new Map([['test.js', { content: 'function test() {}' }]]);
  const patterns = new Map();
  const flows = new Map();
  const config = { framework: 'test' };

  const genome = encoder.encode(files, patterns, flows, config);
  assertContains(genome, 'GENOME', 'Should include GENOME prefix');
  assertContains(genome, 'VERSION:v25', 'Should include version');
});

test('GenomeEncoder decodes genome string', () => {
  const encoder = new GenomeEncoder();
  const genome = 'GENOME|VERSION:v25|ENTITIES:["Test"]|CONFIG:{}|LIBRARY:[]';
  const decoded = encoder.decode(genome);
  assertTrue(decoded !== undefined, 'Should decode genome');
});

test('GenomeEncoder generates stats', () => {
  const encoder = new GenomeEncoder();
  const genome = 'GENOME|VERSION:v25|PATTERN:test|FLOW:auth|ENTITIES:["A"]|CONFIG:{}|LIBRARY:[]';
  const stats = encoder.getStats(genome);
  assertTrue(stats.length > 0, 'Should have length');
});

// ============================================
// Palace Tests
// ============================================

test('Palace initializes', () => {
  const palace = new Palace('.');
  assertTrue(palace !== undefined, 'Should create Palace instance');
});

test('Palace scans directory', async () => {
  const palace = new Palace('.');
  const result = await palace.scan();
  assertTrue(result.files > 0, 'Should find files');
  assertTrue(result.lines > 0, 'Should count lines');
});

test('Palace generates genome', async () => {
  const palace = new Palace('.');
  await palace.scan();
  const genome = await palace.generateGenome();
  // generateGenome returns a genome string or false if no files
  assertTrue(typeof genome === 'string' || genome === false, 'Should return string or false');
  if (typeof genome === 'string') {
    assertContains(genome, 'GENOME', 'Should include GENOME prefix');
  }
});

// ============================================
// Reconstructor Tests
// ============================================

test('Reconstructor initializes', () => {
  const recon = new Reconstructor();
  assertTrue(recon !== undefined, 'Should create Reconstructor instance');
});

test('Reconstructor expands pattern', () => {
  const recon = new Reconstructor();
  const code = recon.reconstructPattern('CRUD_ENTITY', {
    action: 'get',
    entity: 'User',
    method: 'findUnique'
  });
  assertContains(code, 'getUser', 'Should include function name');
});

test('Reconstructor verifies content', () => {
  const recon = new Reconstructor();
  const original = 'function test() { return 1; }';
  const reconstructed = 'function test() { return 1; }';
  assertTrue(recon.verify(original, reconstructed), 'Should verify matching content');
});

// ============================================
// Run Tests
// ============================================

async function runTests() {
  console.log('🧪 LLMemory-Palace v25.0 Test Suite\n');
  console.log('═'.repeat(50));
  console.log('');

  for (const { name, fn } of tests) {
    try {
      await fn();
      console.log(`✅ ${name}`);
      passed++;
    } catch (e) {
      console.log(`❌ ${name}`);
      console.log(`   Error: ${e.message}`);
      failed++;
    }
  }

  console.log('');
  console.log('═'.repeat(50));
  console.log(`📊 Results: ${passed} passed, ${failed} failed`);
  console.log('═'.repeat(50));

  if (failed > 0) {
    process.exit(1);
  }
}

runTests();

